INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-pre-info-tr', 'cp-pre-info', 'tr', 'Ön Bilgilendirme Formu', 'on-bilgilendirme-formu', '{"html": "<h2>Ön Bilgilendirme Formu</h2><h3>1. Satıcı / Hizmet Sağlayıcı Bilgileri</h3><p>Ticari Unvan: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Marka: Gold Mood Astro<br>MERSİS No: 0632143381600001<br>Vergi Dairesi: Büyükçekmece Vergi Dairesi<br>Vergi No: 6321433816<br>Ticaret Sicil No: 491688-5<br>Adres: Cumhuriyet Mahallesi D-100 Karayolu Caddesi ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Telefon: 0212 807 09 59<br>E-posta: goldmoodastro@gmail.com</p><h3>2. Hizmet Bilgileri</h3><p>Satın alınan hizmete ilişkin aşağıdaki bilgiler ödeme ekranında kullanıcıya gösterilir:</p><ul><li>Danışman</li><li>Hizmet Türü</li><li>Görüşme Şekli (Sesli / Görüntülü / Mesajlaşma)</li><li>Görüşme Tarihi</li><li>Görüşme Saati</li><li>Görüşme Süresi</li><li>Hizmet Bedeli</li><li>KDV</li><li>Toplam Ödenecek Tutar</li><li>Ödeme Yöntemi</li></ul><h3>3. Hizmetin Kapsamı</h3><p>Gold Mood Astro, kullanıcılarına çevrim içi astroloji, tarot, numeroloji ve benzeri kişisel farkındalık odaklı danışmanlık hizmetleri sunar. Sunulan hizmetler yalnızca kişisel farkındalık, kişisel gelişim, kişisel değerlendirme, eğlence amacı taşır. Platform ve danışmanlar; kesin gelecek tahmini, garanti sonuç, sağlık teşhisi, tedavi önerisi, hukuki danışmanlık, yatırım tavsiyesi, finansal garanti, bahis veya şans oyunu tahmini, büyü, ritüel, bağlama veya benzeri vaatler sunmaz.</p><h3>4. Cayma Hakkı Bilgilendirmesi</h3><p>Mesafeli Sözleşmeler Yönetmeliği’nin 15/1-ğ maddesi uyarınca, elektronik ortamda anında ifa edilen veya tüketiciye anında teslim edilen hizmetlerde cayma hakkı istisnası uygulanabilir. Kullanıcı, hizmetin ifasına başlanmasını açıkça onayladığında ve cayma hakkını kaybedeceğini kabul ettiğinde, hizmet başladıktan sonra cayma hakkını kullanamaz.</p><h3>5. İptal ve İade Bilgilendirmesi</h3><p>Görüşme başlangıcından 24 saat öncesine kadar ücretsiz iptal yapılabilir. Görüşme başladıktan sonra hizmet ifa edilmiş kabul edilir ve iade yapılmaz. Danışmanın katılmaması veya Platform kaynaklı teknik sorunlarda kullanıcıya yeni randevu veya ücret iadesi sunulabilir.</p><h3>6. Başvuru Yolları</h3><p>Uyuşmazlıklarda Ticaret Bakanlığı tarafından ilan edilen parasal sınırlar dahilinde Tüketici Hakem Heyetleri ve Tüketici Mahkemelerine başvurulabilir.</p><h3>7. Onay</h3><p>Kullanıcı, ödeme işleminden önce bu Ön Bilgilendirme Formu’nu okuyup kabul ettiğini beyan eder.</p>"}', 'Sipariş öncesi yasal ön bilgilendirme.', 'Ön Bilgilendirme Formu — Gold Mood Astro', 'Gold Mood Astro dijital danışmanlık hizmetleri için mesafeli satış ön bilgilendirme formu.'),
  ('cpi-pre-info-en', 'cp-pre-info', 'en', 'Pre-Contract Information Form', 'pre-contract-information', '{"html": "<h2>Pre-Contract Information Form</h2><h3>1. Seller / Service Provider</h3><p>Legal name: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Brand: Gold Mood Astro<br>MERSİS No: 0632143381600001<br>Tax office: Büyükçekmece<br>Tax No: 6321433816<br>Trade Registry No: 491688-5<br>Address: Cumhuriyet Mah. D-100 Karayolu Cad. ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Phone: +90 212 807 09 59<br>Email: goldmoodastro@gmail.com</p><h3>2. Service Details</h3><p>The following details are shown on the payment screen:</p><ul><li>Consultant</li><li>Service type</li><li>Session format (Audio / Video / Messaging)</li><li>Date</li><li>Time</li><li>Duration</li><li>Service fee</li><li>VAT</li><li>Total amount payable</li><li>Payment method</li></ul><h3>3. Scope of Service</h3><p>Gold Mood Astro provides online astrology, tarot, numerology and similar awareness-focused consulting. Services are for personal awareness, personal development, personal reflection, entertainment only. The Platform and consultants do not provide definite predictions of the future, guaranteed outcomes, medical diagnosis, treatment advice, legal advice, investment advice, financial guarantees, betting or games-of-chance predictions, spells, rituals, binding or similar promises.</p><h3>4. Withdrawal Right Notice</h3><p>Under Article 15/1-ğ of the Regulation on Distance Contracts, the withdrawal-right exception may apply to services performed instantly. Once the user expressly consents to commencement and accepts loss of the right, it cannot be used after the service begins.</p><h3>5. Cancellation and Refund Notice</h3><p>Free cancellation up to 24 hours before the session. After the session begins the service is deemed performed and no refund is made. A new appointment or refund may be offered if the consultant does not attend or a platform-side issue occurs.</p><h3>6. Complaint Channels</h3><p>Consumer Arbitration Committees and Consumer Courts may be addressed within the monetary limits announced by the Ministry of Trade.</p><h3>7. Consent</h3><p>Before payment, the user declares having read and accepted this Pre-Contract Information Form.</p>"}', 'Legal pre-contract information before ordering.', 'Pre-Contract Information Form — Gold Mood Astro', 'Distance sales pre-contract information for Gold Mood Astro digital services.'),
  ('cpi-pre-info-de', 'cp-pre-info', 'de', 'Vorvertragliche Informationen', 'vorvertragliche-informationen', '{"html": "<h2>Vorvertragliche Informationen</h2><h3>1. Verkäufer / Diensteanbieter</h3><p>Firmenname: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Marke: Gold Mood Astro<br>MERSİS-Nr.: 0632143381600001<br>Finanzamt: Büyükçekmece<br>Steuernr.: 6321433816<br>Handelsregisternr.: 491688-5<br>Adresse: Cumhuriyet Mah. D-100 Karayolu Cad. ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Telefon: +90 212 807 09 59<br>E-Mail: goldmoodastro@gmail.com</p><h3>2. Leistungsdetails</h3><p>Folgende Angaben werden im Zahlungsbildschirm angezeigt:</p><ul><li>Berater</li><li>Leistungsart</li><li>Sitzungsform (Audio / Video / Nachricht)</li><li>Datum</li><li>Uhrzeit</li><li>Dauer</li><li>Leistungsentgelt</li><li>MwSt.</li><li>Zu zahlender Gesamtbetrag</li><li>Zahlungsart</li></ul><h3>3. Leistungsumfang</h3><p>Gold Mood Astro bietet Online-Astrologie, -Tarot, -Numerologie und ähnliche achtsamkeitsorientierte Beratung. Die Leistungen dienen nur der persönliche Achtsamkeit, persönliche Entwicklung, persönliche Reflexion, Unterhaltung. Plattform und Berater bieten keine sichere Zukunftsvorhersagen, garantierte Ergebnisse, medizinische Diagnosen, Behandlungsempfehlungen, Rechtsberatung, Anlageberatung, finanzielle Garantien, Wett- oder Glücksspielprognosen, Zauber, Rituale, Bindungen oder ähnliche Versprechen.</p><h3>4. Hinweis zum Widerrufsrecht</h3><p>Gemäß Art. 15/1-ğ der Fernabsatzverordnung kann die Ausnahme gelten. Nach ausdrücklicher Zustimmung zum Leistungsbeginn und Akzeptanz des Rechtsverlusts kann das Widerrufsrecht nach Leistungsbeginn nicht ausgeübt werden.</p><h3>5. Hinweis zu Stornierung und Erstattung</h3><p>Kostenlose Stornierung bis 24 Stunden vor der Sitzung. Nach Beginn gilt die Leistung als erbracht, keine Erstattung. Bei Nichterscheinen oder plattformseitigen Problemen neuer Termin oder Erstattung möglich.</p><h3>6. Beschwerdewege</h3><p>Verbraucherschlichtungsstellen und Verbrauchergerichte im Rahmen der Grenzen des Handelsministeriums.</p><h3>7. Zustimmung</h3><p>Vor der Zahlung erklärt der Nutzer, diese vorvertraglichen Informationen gelesen und akzeptiert zu haben.</p>"}', 'Rechtliche vorvertragliche Informationen.', 'Vorvertragliche Informationen — Gold Mood Astro', 'Fernabsatz-Vorabinformation für digitale Gold Mood Astro-Dienste.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), content = VALUES(content),
  summary = VALUES(summary), meta_title = VALUES(meta_title), meta_description = VALUES(meta_description);

