INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-distance-sales-tr', 'cp-distance-sales', 'tr', 'Mesafeli Hizmet Sözleşmesi', 'mesafeli-satis-sozlesmesi', '{"html": "<h2>Mesafeli Hizmet Sözleşmesi</h2><h3>1. Taraflar</h3><p>İşbu Mesafeli Hizmet Sözleşmesi, Gold Mood Astro markası altında hizmet sunan QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ ile Platform üzerinden hizmet satın alan kullanıcı arasında elektronik ortamda kurulmuştur.</p><h3>2. Satıcı / Hizmet Sağlayıcı Bilgileri</h3><p>Ticari Unvan: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Marka: Gold Mood Astro<br>MERSİS No: 0632143381600001<br>Vergi Dairesi: Büyükçekmece Vergi Dairesi<br>Vergi No: 6321433816<br>Ticaret Sicil No: 491688-5<br>Adres: Cumhuriyet Mahallesi D-100 Karayolu Caddesi ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Telefon: 0212 807 09 59<br>E-posta: goldmoodastro@gmail.com</p><h3>3. Sözleşmenin Konusu</h3><p>İşbu sözleşmenin konusu, kullanıcının Gold Mood Astro platformu üzerinden elektronik ortamda satın aldığı çevrim içi danışmanlık hizmetinin sunulmasına ilişkin tarafların hak ve yükümlülüklerinin belirlenmesidir.</p><h3>4. Platformun Hizmet Modeli</h3><p>Gold Mood Astro, çevrim içi danışmanlık hizmetlerini kendi adına kullanıcılarına sunan dijital bir platformdur. Platform kapsamında hizmet veren danışmanlar, Gold Mood Astro’ya hizmet sağlayan bağımsız hizmet tedarikçileridir. Danışmanların yorumları kişisel değerlendirme niteliğindedir; Gold Mood Astro, danışmanlık sonucuna ilişkin herhangi bir garanti vermez.</p><h3>5. Hizmetin Niteliği</h3><p>Platformda sunulan astroloji, tarot, numeroloji ve benzeri danışmanlık hizmetleri; kişisel farkındalık, kişisel gelişim, kişisel değerlendirme, eğlence amacıyla sunulmaktadır. Platform ve danışmanlar; kesin gelecek tahmini, garanti sonuç, sağlık teşhisi, tedavi önerisi, hukuki danışmanlık, yatırım tavsiyesi, finansal garanti, bahis veya şans oyunu tahmini, büyü, ritüel, bağlama veya benzeri vaatler sunmaz.</p><h3>6. Hizmet Bilgileri</h3><p>Satın alınan hizmete ilişkin bilgiler ödeme ekranında kullanıcıya gösterilir. Bu bilgiler; danışman adı, hizmet türü, görüşme şekli, görüşme tarihi, görüşme saati, görüşme süresi, hizmet bedeli ve KDV dahil toplam ödeme tutarı alanlarından oluşur.</p><h3>7. Ücret ve Ödeme</h3><p>Hizmet bedeli, ödeme ekranında KDV dahil toplam tutar olarak gösterilir. Ödemeler lisanslı ödeme kuruluşları aracılığıyla gerçekleştirilir. Gold Mood Astro kullanıcıların banka veya kredi kartı bilgilerini kendi sistemlerinde saklamaz.</p><h3>8. Cayma Hakkı</h3><p>Mesafeli Sözleşmeler Yönetmeliği’nin 15/1-ğ maddesi uyarınca, elektronik ortamda anında ifa edilen veya tüketiciye anında teslim edilen hizmetlerde cayma hakkı istisnası uygulanabilir. Kullanıcı, ödeme adımında hizmetin ifasına başlanmasını açıkça onayladığı ve cayma hakkını kaybedeceğini kabul ettiği takdirde, hizmet başladıktan sonra cayma hakkını kullanamaz.</p><h3>9. İptal ve İade</h3><p>İptal ve iade süreçleri Gold Mood Astro İptal ve İade Politikası kapsamında yürütülür. Kullanıcı, görüşme başlamadan 24 saat öncesine kadar ücretsiz iptal talebinde bulunabilir. Görüşme başladıktan sonra hizmet ifa edilmiş sayılır ve ücret iadesi yapılmaz. Danışmanın görüşmeye katılmaması veya Platform kaynaklı teknik arıza yaşanması halinde kullanıcıya yeni randevu veya ücret iadesi seçeneği sunulabilir.</p><h3>10. Teknik Sorunlar</h3><p>Platform kaynaklı teknik sorunlarda durum teknik ekip tarafından incelenir. İnceleme sonucunda ücretsiz yeni randevu, hizmet süresinin telafisi veya ücret iadesi seçeneklerinden biri uygulanabilir.</p><h3>11. 18 Yaş Şartı</h3><p>Platform yalnızca 18 yaşını doldurmuş kullanıcılar tarafından kullanılabilir. 18 yaşından küçük kişilerin Platform üzerinden hizmet satın alması yasaktır.</p><h3>12. Uyuşmazlık</h3><p>İşbu sözleşmeden kaynaklanan uyuşmazlıklarda Türkiye Cumhuriyeti mevzuatı uygulanır. Tüketici işlemlerinde, Ticaret Bakanlığı tarafından ilan edilen parasal sınırlar dahilinde Tüketici Hakem Heyetleri ve Tüketici Mahkemeleri yetkilidir.</p><h3>13. Yürürlük</h3><p>Kullanıcı, ödeme işlemini tamamlayarak işbu Mesafeli Hizmet Sözleşmesi’ni okuduğunu, anladığını ve kabul ettiğini beyan eder.</p>"}', 'Gold Mood Astro dijital hizmetleri için mesafeli satış koşulları.', 'Mesafeli Hizmet Sözleşmesi — Gold Mood Astro', 'Gold Mood Astro çevrim içi danışmanlık hizmetleri için mesafeli hizmet sözleşmesi.'),
  ('cpi-distance-sales-en', 'cp-distance-sales', 'en', 'Distance Service Agreement', 'distance-sales-agreement', '{"html": "<h2>Distance Service Agreement</h2><h3>1. Parties</h3><p>This Distance Service Agreement is concluded electronically between QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ, operating under the Gold Mood Astro brand, and the user who purchases services through the Platform.</p><h3>2. Seller / Service Provider</h3><p>Legal name: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Brand: Gold Mood Astro<br>MERSİS No: 0632143381600001<br>Tax office: Büyükçekmece<br>Tax No: 6321433816<br>Trade Registry No: 491688-5<br>Address: Cumhuriyet Mah. D-100 Karayolu Cad. ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Phone: +90 212 807 09 59<br>Email: goldmoodastro@gmail.com</p><h3>3. Subject</h3><p>This agreement defines the rights and obligations of the parties regarding the online consulting service the user purchases electronically through the Gold Mood Astro platform.</p><h3>4. Service Model</h3><p>Gold Mood Astro is a digital platform that provides online consulting services to its users in its own name. Consultants are independent service suppliers to Gold Mood Astro. Consultant interpretations are personal opinions; Gold Mood Astro gives no guarantee as to any outcome.</p><h3>5. Nature of the Service</h3><p>Astrology, tarot, numerology and similar consulting services are offered for personal awareness, personal development, personal reflection, entertainment purposes only. The Platform and consultants do not provide definite predictions of the future, guaranteed outcomes, medical diagnosis, treatment advice, legal advice, investment advice, financial guarantees, betting or games-of-chance predictions, spells, rituals, binding or similar promises.</p><h3>6. Service Details</h3><p>Details of the purchased service are shown on the payment screen: consultant name, service type, session format, date, time, duration, price and total amount including VAT.</p><h3>7. Price and Payment</h3><p>The price is shown VAT-included on the payment screen. Payments are processed by licensed payment institutions. Gold Mood Astro does not store users’ card details.</p><h3>8. Right of Withdrawal</h3><p>Under Article 15/1-ğ of the Regulation on Distance Contracts, the withdrawal-right exception may apply to services performed instantly in electronic form. If the user, at the payment step, expressly consents to the commencement of performance and accepts loss of the withdrawal right, the right cannot be exercised once the service has begun.</p><h3>9. Cancellation and Refund</h3><p>Handled under the Cancellation and Refund Policy. The user may cancel free of charge up to 24 hours before the session. Once the session begins the service is deemed performed and no refund is made. If the consultant does not attend or a platform-side technical failure occurs, a new appointment or refund may be offered.</p><h3>10. Technical Issues</h3><p>Platform-side technical issues are reviewed by the technical team; a free new appointment, compensation of time, or a refund may be applied.</p><h3>11. Minimum Age</h3><p>The Platform may only be used by users aged 18 or over. Purchases by persons under 18 are prohibited.</p><h3>12. Disputes</h3><p>The laws of the Republic of Türkiye apply. Consumer Arbitration Committees and Consumer Courts are competent within the monetary limits announced by the Ministry of Trade.</p><h3>13. Entry into Force</h3><p>By completing payment, the user declares that they have read, understood and accepted this Distance Service Agreement.</p>"}', 'Distance sales terms for Gold Mood Astro digital services.', 'Distance Service Agreement — Gold Mood Astro', 'Distance service agreement for Gold Mood Astro online consulting.'),
  ('cpi-distance-sales-de', 'cp-distance-sales', 'de', 'Fernabsatzvertrag', 'fernabsatzvertrag', '{"html": "<h2>Fernabsatz-Dienstleistungsvertrag</h2><h3>1. Parteien</h3><p>Dieser Vertrag wird elektronisch zwischen der unter der Marke Gold Mood Astro tätigen QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ und dem über die Plattform kaufenden Nutzer geschlossen.</p><h3>2. Verkäufer / Diensteanbieter</h3><p>Firmenname: QUEBAB GIDA FABRİKASI RESTORAN İŞLETMECİLİĞİ EĞLENCE ORGANİZASYON VE KİRALAMA TİCARET LİMİTED ŞİRKETİ<br>Marke: Gold Mood Astro<br>MERSİS-Nr.: 0632143381600001<br>Finanzamt: Büyükçekmece<br>Steuernr.: 6321433816<br>Handelsregisternr.: 491688-5<br>Adresse: Cumhuriyet Mah. D-100 Karayolu Cad. ADM Konaklama Sitesi Outlet Park AVM No:374 İç Kapı No:63 Büyükçekmece / İstanbul<br>Telefon: +90 212 807 09 59<br>E-Mail: goldmoodastro@gmail.com</p><h3>3. Gegenstand</h3><p>Dieser Vertrag regelt die Rechte und Pflichten der Parteien in Bezug auf die vom Nutzer elektronisch erworbene Online-Beratungsleistung.</p><h3>4. Dienstmodell</h3><p>Gold Mood Astro ist eine digitale Plattform, die Online-Beratung im eigenen Namen anbietet. Berater sind unabhängige Dienstleister von Gold Mood Astro. Beraterdeutungen sind persönliche Einschätzungen; es wird keine Garantie für ein Ergebnis gegeben.</p><h3>5. Art der Leistung</h3><p>Astrologie, Tarot, Numerologie und ähnliche Beratungen werden ausschließlich zu Zwecken der persönliche Achtsamkeit, persönliche Entwicklung, persönliche Reflexion, Unterhaltung angeboten. Plattform und Berater bieten keine sichere Zukunftsvorhersagen, garantierte Ergebnisse, medizinische Diagnosen, Behandlungsempfehlungen, Rechtsberatung, Anlageberatung, finanzielle Garantien, Wett- oder Glücksspielprognosen, Zauber, Rituale, Bindungen oder ähnliche Versprechen.</p><h3>6. Leistungsdetails</h3><p>Die Details werden im Zahlungsbildschirm angezeigt: Beratername, Leistungsart, Sitzungsform, Datum, Uhrzeit, Dauer, Preis und Gesamtbetrag inkl. MwSt.</p><h3>7. Preis und Zahlung</h3><p>Der Preis wird inkl. MwSt. angezeigt. Zahlungen erfolgen über lizenzierte Zahlungsinstitute. Kartendaten werden nicht gespeichert.</p><h3>8. Widerrufsrecht</h3><p>Gemäß Art. 15/1-ğ der Fernabsatzverordnung kann bei elektronisch sofort erbrachten Leistungen die Ausnahme vom Widerrufsrecht gelten. Stimmt der Nutzer im Zahlungsschritt dem sofortigen Leistungsbeginn ausdrücklich zu und akzeptiert den Verlust des Widerrufsrechts, kann dieses nach Leistungsbeginn nicht mehr ausgeübt werden.</p><h3>9. Stornierung und Erstattung</h3><p>Nach der Stornierungs- und Erstattungsrichtlinie. Kostenlose Stornierung bis 24 Stunden vor der Sitzung. Nach Sitzungsbeginn gilt die Leistung als erbracht, keine Erstattung. Bei Nichterscheinen des Beraters oder plattformseitigem technischen Fehler kann ein neuer Termin oder eine Erstattung angeboten werden.</p><h3>10. Technische Probleme</h3><p>Plattformseitige Probleme werden vom technischen Team geprüft; neuer Termin, Zeitausgleich oder Erstattung möglich.</p><h3>11. Mindestalter</h3><p>Die Plattform darf nur von Personen ab 18 Jahren genutzt werden.</p><h3>12. Streitigkeiten</h3><p>Es gilt das Recht der Republik Türkei. Zuständig sind Verbraucherschlichtungsstellen und Verbrauchergerichte im Rahmen der vom Handelsministerium bekannt gegebenen Grenzen.</p><h3>13. Inkrafttreten</h3><p>Mit Abschluss der Zahlung erklärt der Nutzer, diesen Vertrag gelesen, verstanden und akzeptiert zu haben.</p>"}', 'Fernabsatzbedingungen für digitale Gold Mood Astro-Dienste.', 'Fernabsatzvertrag — Gold Mood Astro', 'Fernabsatz-Dienstleistungsvertrag für Gold Mood Astro Online-Beratung.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), content = VALUES(content),
