INSERT INTO custom_pages_i18n (id, custom_page_id, locale, title, slug, content, summary, meta_title, meta_description) VALUES
  ('cpi-cancel-refund-tr', 'cp-cancel-refund', 'tr', 'İptal ve İade Politikası', 'iptal-iade-politikasi', '{"html": "<h2>İptal ve İade Politikası</h2><h3>1. Genel İlke</h3><p>Gold Mood Astro’da sunulan hizmetler çevrim içi danışmanlık hizmetidir. İptal ve iade süreçleri, hizmetin başlayıp başlamadığına, danışmanın katılım durumuna ve teknik aksaklığın kaynağına göre değerlendirilir.</p><h3>2. Görüşmeden Önce İptal</h3><p>Kullanıcı, görüşme başlangıç saatinden 24 saat öncesine kadar ücretsiz iptal talebinde bulunabilir. Bu durumda ücret iadesi yapılabilir veya kullanıcıya yeni randevu oluşturma hakkı tanınabilir.</p><h3>3. Görüşmeye 24 Saatten Az Kala İptal</h3><p>Görüşmeye 24 saatten az süre kala yapılan iptal taleplerinde ücret iadesi yapılmayabilir. Bu durumda danışmanın uygunluğu ve Platform değerlendirmesi doğrultusunda randevu değişikliği yapılabilir.</p><h3>4. Görüşme Başladıktan Sonra İade</h3><p>Görüşme başladıktan sonra danışmanlık hizmeti ifa edilmiş sayılır. Bu aşamadan sonra ücret iadesi yapılmaz.</p><h3>5. Danışmanın Görüşmeye Katılmaması</h3><p>Danışmanın görüşmeye katılmaması halinde kullanıcıya tam ücret iadesi veya ücretsiz yeni randevu seçeneklerinden biri sunulur.</p><h3>6. Platform Kaynaklı Teknik Arıza</h3><p>Platformdan kaynaklanan teknik arızalarda durum teknik ekip tarafından incelenir. İnceleme sonucunda kullanıcıya ücretsiz yeni randevu, hizmet süresinin telafisi veya tam ya da kısmi iade seçeneklerinden biri sunulabilir.</p><h3>7. Kullanıcı Kaynaklı Teknik Sorunlar</h3><p>Kullanıcının internet bağlantısı, cihazı, kamera, mikrofon, tarayıcı veya uygulama izinlerinden kaynaklanan sorunlarda Platform iade yapmakla yükümlü değildir. Ancak uygun görülmesi halinde kullanıcıya yeni randevu desteği sağlanabilir.</p><h3>8. Mücbir Sebep</h3><p>Deprem, sel, yangın, elektrik kesintisi, internet altyapı kesintisi, resmi makam kararları ve benzeri mücbir sebepler halinde taraflara yeni randevu oluşturma imkânı tanınabilir.</p><h3>9. İade Süresi</h3><p>Onaylanan iadeler, ödeme kuruluşu ve bankaların işlem sürelerine bağlı olarak kullanıcının ödeme yaptığı karta veya hesaba aktarılır. Bankadan kaynaklanan gecikmelerden Platform sorumlu değildir.</p>"}', 'Gold Mood Astro iptal, cayma ve iade koşulları.', 'İptal ve İade Politikası — Gold Mood Astro', 'Gold Mood Astro seans, kredi ve abonelikler için iptal ve iade politikası.'),
  ('cpi-cancel-refund-en', 'cp-cancel-refund', 'en', 'Cancellation and Refund Policy', 'cancellation-refund-policy', '{"html": "<h2>Cancellation and Refund Policy</h2><h3>1. General Principle</h3><p>Services on Gold Mood Astro are online consulting services. Cancellation and refund are assessed based on whether the service has started, the consultant’s attendance, and the source of any technical fault.</p><h3>2. Cancellation Before the Session</h3><p>The user may cancel free of charge up to 24 hours before the start time. A refund may be issued or a new appointment offered.</p><h3>3. Cancellation Less Than 24 Hours Before</h3><p>For cancellations made less than 24 hours before, a refund may not be issued. A reschedule may be arranged subject to consultant availability and Platform review.</p><h3>4. Refund After the Session Starts</h3><p>Once the session begins the service is deemed performed and no refund is made.</p><h3>5. Consultant Does Not Attend</h3><p>If the consultant does not attend, the user is offered a full refund or a free new appointment.</p><h3>6. Platform-Side Technical Failure</h3><p>Platform-side failures are reviewed by the technical team; a free new appointment, time compensation, or a full/partial refund may be offered.</p><h3>7. User-Side Technical Issues</h3><p>For issues arising from the user’s connection, device, camera, microphone, browser or app permissions, the Platform is not obliged to refund, though a new appointment may be supported where appropriate.</p><h3>8. Force Majeure</h3><p>In cases of earthquake, flood, fire, power/internet outage, official decisions and similar force majeure, the parties may be offered a new appointment.</p><h3>9. Refund Time</h3><p>Approved refunds are transferred to the card/account used, subject to payment-institution and bank processing times. The Platform is not responsible for bank delays.</p>"}', 'Gold Mood Astro cancellation and refund terms.', 'Cancellation and Refund Policy — Gold Mood Astro', 'Gold Mood Astro cancellation and refund policy.'),
  ('cpi-cancel-refund-de', 'cp-cancel-refund', 'de', 'Stornierungs- und Erstattungsrichtlinie', 'stornierung-erstattung', '{"html": "<h2>Stornierungs- und Erstattungsrichtlinie</h2><h3>1. Allgemeiner Grundsatz</h3><p>Die Leistungen sind Online-Beratungen. Stornierung und Erstattung richten sich danach, ob die Leistung begonnen hat, ob der Berater teilnimmt und woher eine technische Störung stammt.</p><h3>2. Stornierung vor der Sitzung</h3><p>Kostenlose Stornierung bis 24 Stunden vor Beginn. Erstattung oder neuer Termin möglich.</p><h3>3. Stornierung weniger als 24 Stunden vorher</h3><p>Hier ggf. keine Erstattung; ein neuer Termin kann je nach Verfügbarkeit und Prüfung angeboten werden.</p><h3>4. Erstattung nach Sitzungsbeginn</h3><p>Nach Beginn gilt die Leistung als erbracht, keine Erstattung.</p><h3>5. Berater nimmt nicht teil</h3><p>Volle Erstattung oder kostenloser neuer Termin.</p><h3>6. Plattformseitige Störung</h3><p>Prüfung durch das technische Team; neuer Termin, Zeitausgleich oder volle/teilweise Erstattung möglich.</p><h3>7. Nutzerseitige Probleme</h3><p>Bei Problemen mit Verbindung, Gerät, Kamera, Mikrofon, Browser oder App-Berechtigungen besteht keine Erstattungspflicht; ggf. neuer Termin.</p><h3>8. Höhere Gewalt</h3><p>Bei Erdbeben, Überschwemmung, Brand, Strom-/Internetausfall, behördlichen Entscheidungen u. Ä. kann ein neuer Termin angeboten werden.</p><h3>9. Erstattungsdauer</h3><p>Genehmigte Erstattungen erfolgen auf die verwendete Karte/das Konto, abhängig von Zahlungsinstitut und Bank. Keine Haftung für Bankverzögerungen.</p>"}', 'Gold Mood Astro Storno- und Erstattungsbedingungen.', 'Stornierungs- und Erstattungsrichtlinie — Gold Mood Astro', 'Gold Mood Astro Richtlinie für Stornierung und Erstattung.')
ON DUPLICATE KEY UPDATE
  title = VALUES(title), slug = VALUES(slug), content = VALUES(content),
  summary = VALUES(summary), meta_title = VALUES(meta_title), meta_description = VALUES(meta_description);
